<template><div class='fixed bottom-0 left-0 right-0 p-3 bg-gray-100 flex gap-2'><span>{{ title }}</span><button @click='p.togglePlay()'>{{ p.isPlaying?'Pause':'Play' }}</button><button @click='p.prev()'>Prev</button><button @click='p.next()'>Next</button><button @click='p.toggleShuffle()'>Shuffle {{ p.shuffle?'On':'Off' }}</button><button @click='p.cycleRepeat()'>Repeat {{ p.repeat }}</button></div></template>
<script setup lang='ts'>import { computed } from 'vue'; import { usePlayerStore } from '../stores/player'; const p=usePlayerStore(); const title=computed(()=>p.currentTrack?.title || 'No track');</script>
